{"code":"import numpy as np
from scipy.optimize import brentq

V = 150_000
log_V = np.log(V)
target_fk = 10.0
target_bk = 10.0

def fk_for_p(p, k):
    if p <= 0 or p >= 1/k:
        return np.inf
    q = (1 - k*p) / (V - k)
    if q <= 0:
        return np.inf
    H = -k*p*np.log(p) - (V-k)*q*np.log(q)
    return log_V - H

def bk_for_p(p, k):
    if p <= 0 or p >= 1/k:
        return np.inf
    q = (1 - k*p) / (V - k)
    if q <= 0:
        return np.inf
    sum_log = k*np.log(p) + (V-k)*np.log(q)
    return -sum_log / V

# For a given k, find p such that FK=10, then check BK
for k in range(2, 200):
    def fk_diff(p):
        return fk_for_p(p, k) - target_fk

    try:
        p_low = 1e-15
        p_high = (1 - 1e-15) / k

        fk_low = fk_for_p(p_low, k)
        fk_high = fk_for_p(p_high, k)

        if fk_low < target_fk and fk_high > target_fk:
            p_sol = brentq(fk_diff, p_low, p_high)
            bk_val = bk_for_p(p_sol, k)

            print(f"k={k}: FK=10 at p={p_sol:.12e}, BK={bk_val:.6f}")
    except Exception as e:
        pass
